        "op": "evaluate",
        "source": "(< 1 3 2)"
      },
      "expected_output": "False"
    },
    {
      "input": {
        "op": "evaluate",
        "source": "(and 1 0 3)"
      },
      "expected_output": "0"
    },
    {
      "input": {
        "op": "evaluate",
        "source": "(or 0 False 5)"
      },
      "expected_output": "5"
