    {
      "input": {
        "op": "parse",
        "source": "1,000_000"
      },
      "expected_output": "Integer(1000000)"
    },
    {
      "input": {
        "op": "parse",
        "source": "NaN"
      },
      "expected_output": "Float(nan)"
    },
    {
      "input": {
        "op": "parse",
        "source": "nan"
      },
      "expected_output": "Symbol(nan)"
    },
